/** Format time remaining with urgency class */
export function formatTimeLeft(expiresAt: string | null): { label: string; sublabel: string; cls: string; ticking: boolean } {
    if (!expiresAt) return { label: "—", sublabel: "", cls: "normal", ticking: false }
    const diff = new Date(expiresAt).getTime() - Date.now()
    if (diff <= 0) return { label: "Ended", sublabel: "", cls: "urgent", ticking: false }
    const totalSecs = Math.floor(diff / 1000)
    const totalMins = Math.floor(totalSecs / 60)
    const h = Math.floor(totalMins / 60)
    const m = totalMins % 60
    const s = totalSecs % 60
    const d = Math.floor(h / 24)
    const remH = h % 24
    const mm = String(m).padStart(2, "0")
    const ss = String(s).padStart(2, "0")
    const hh = String(remH).padStart(2, "0")
    /* < 6h: show seconds, tick every second */
    if (h < 1) return { label: `${mm}m:${ss}s`, sublabel: "remaining", cls: "urgent", ticking: true }
    if (h < 6) return { label: `${h}h:${mm}m:${ss}s`, sublabel: "remaining", cls: "urgent", ticking: true }
    if (d < 2) return { label: `${h}h:${mm}m`, sublabel: "remaining", cls: "warning", ticking: false }
    return { label: `${d}d:${hh}h:${mm}m`, sublabel: "remaining", cls: "normal", ticking: false }
}

/** Short format for compact displays (grid cards, table) */
export function formatTimeShort(expiresAt: string | null): { label: string; cls: string } {
    if (!expiresAt) return { label: "No deadline", cls: "normal" }
    const diff = new Date(expiresAt).getTime() - Date.now()
    if (diff <= 0) return { label: "Ended", cls: "urgent" }
    const h = Math.floor(diff / 3600000)
    const d = Math.floor(h / 24)
    if (h < 6) return { label: `${h}h`, cls: "urgent" }
    if (d < 2) return { label: `${h}h`, cls: "warning" }
    return { label: `${d}d`, cls: "normal" }
}

/** Map quest type to CSS badge class */
export function typeBadgeClass(type: string): string {
    const map: Record<string, string> = {
        FCFS: "badge-fcfs",
        LEADERBOARD: "badge-leaderboard",
        LUCKY_DRAW: "badge-luckydraw",
    }
    return map[type] ?? "badge-fcfs"
}

/** Map quest type to text color class */
export function typeColorClass(type: string): string {
    return "text-foreground"
}

/** Map quest status to CSS badge class */
export function statusBadgeClass(status: string): string {
    const map: Record<string, string> = {
        live: "badge-live",
        completed: "badge-completed",
        draft: "badge-draft",
        scheduled: "badge-scheduled",
        expired: "badge-expired",
        cancelled: "badge-cancelled",
    }
    return map[status] ?? "badge-live"
}

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import { ThemeProvider, useTheme, THEMES } from './ThemeContext'

// Test component that uses the hook
function TestComponent() {
    const { theme, colorMode, setTheme, setColorMode } = useTheme()
    return (
        <div>
            <div data-testid="theme">{theme}</div>
            <div data-testid="color-mode">{colorMode}</div>
            <button onClick={() => setTheme('glass')}>Set Glass</button>
            <button onClick={() => setColorMode('dark')}>Set Dark</button>
        </div>
    )
}

describe('ThemeContext', () => {
    beforeEach(() => {
        localStorage.clear()
        document.documentElement.removeAttribute('data-theme')
        document.documentElement.classList.remove('dark')
    })

    it('should throw error when useTheme is used outside ThemeProvider', () => {
        const consoleError = vi.spyOn(console, 'error').mockImplementation(() => {})
        expect(() => render(<TestComponent />)).toThrow(
            'useTheme must be used within ThemeProvider'
        )
        consoleError.mockRestore()
    })

    it('should provide default theme and color mode', () => {
        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        expect(screen.getByTestId('theme')).toHaveTextContent('terminal')
        expect(screen.getByTestId('color-mode')).toHaveTextContent('light')
    })

    it('should load theme from localStorage', () => {
        localStorage.setItem('cq-theme', 'glass')
        localStorage.setItem('cq-color-mode', 'dark')

        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        expect(screen.getByTestId('theme')).toHaveTextContent('glass')
        expect(screen.getByTestId('color-mode')).toHaveTextContent('dark')
    })

    it('should fallback to default when localStorage has invalid theme', () => {
        localStorage.setItem('cq-theme', 'invalid-theme')
        localStorage.setItem('cq-color-mode', 'invalid-mode')

        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        expect(screen.getByTestId('theme')).toHaveTextContent('terminal')
        expect(screen.getByTestId('color-mode')).toHaveTextContent('light')
    })

    it('should update theme and persist to localStorage', () => {
        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        const setGlassButton = screen.getByText('Set Glass')
        fireEvent.click(setGlassButton)

        expect(screen.getByTestId('theme')).toHaveTextContent('glass')
        expect(localStorage.getItem('cq-theme')).toBe('glass')
    })

    it('should update color mode and persist to localStorage', () => {
        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        const setDarkButton = screen.getByText('Set Dark')
        fireEvent.click(setDarkButton)

        expect(screen.getByTestId('color-mode')).toHaveTextContent('dark')
        expect(localStorage.getItem('cq-color-mode')).toBe('dark')
    })

    it('should apply theme attribute to document root', () => {
        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        expect(document.documentElement.getAttribute('data-theme')).toBe('terminal')
    })

    it('should apply dark class to document root when dark mode', () => {
        localStorage.setItem('cq-color-mode', 'dark')

        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        expect(document.documentElement.classList.contains('dark')).toBe(true)
    })

    it('should remove dark class when light mode', () => {
        localStorage.setItem('cq-color-mode', 'light')

        render(
            <ThemeProvider>
                <TestComponent />
            </ThemeProvider>
        )

        expect(document.documentElement.classList.contains('dark')).toBe(false)
    })

    it('should export all theme options', () => {
        expect(THEMES).toHaveLength(5)
        expect(THEMES.map(t => t.id)).toEqual([
            'terminal',
            'glass',
            'brutalist',
            'minimal',
            'bauhaus',
        ])
    })
})
